import argparse
import json
import os
import numpy as np
from cogniplan_env import ExplorationEnv
import heapq
import torch


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def build_graph(nodes, robot_pos, cur_neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord = tuple(np.round(n["coords"], 6))
        coord_to_idx[coord] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get("neighbors", []):
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(tuple(np.round(nb, 6)))
            else:
                j = int(nb) if (0 <= int(nb) < N) else None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n["coords"], dtype=float) -
                    np.array(nodes[j]["coords"], dtype=float)
                ))
                adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in cur_neighbors:
        j = coord_to_idx.get(tuple(np.round(nb, 6)))
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) -
            np.array(nb, dtype=float)
        ))
        adj[r_idx].append((j, w))
        adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


class Explorer:
    def __init__(self):
        self.step_count = 0
        self.history = []
        self.prev_pos = None
        self.prev_move_dir = None

    def _update_history(self, coord):
        self.history.append(np.array(coord, dtype=float))
        if len(self.history) > 20:
            self.history.pop(0)

    def select_action(self, obs):
        robot_pos = np.array(obs["robot_pos"], dtype=np.float32)
        neighbors = obs["neighbors"]
        nodes = obs["nodes"]
        frontiers = obs.get("frontiers", [])

        if not neighbors:
            return None

        self.step_count += 1
        steps_remaining = max(0, 128 - self.step_count)

        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        # first_step[j] = immediate neighbor index (graph node) on shortest path from robot to j
        first_step = [None] * N
        order = [i for i in range(N) if dist[i] < float('inf') and i != r_idx]
        order.sort(key=lambda i: dist[i])
        for j in order:
            p = prev[j]
            if p == r_idx:
                first_step[j] = j
            else:
                fs = first_step[p] if p is not None else None
                first_step[j] = fs if fs is not None else j

        # map first-step graph node -> neighbor list index
        node_to_neighbor_idx = {}
        for idx, nb in enumerate(neighbors):
            j = coord_to_idx.get(tuple(np.round(nb, 6)))
            if j is not None:
                node_to_neighbor_idx[j] = idx

        scores = np.zeros(len(neighbors), dtype=float)
        history_set = set(tuple(np.round(h, 6)) for h in self.history)

        for j in range(N):
            if j == r_idx:
                continue
            d = dist[j]
            if d == float('inf') or d < 1e-6:
                continue
            fs = first_step[j]
            if fs is None:
                continue
            nb_idx = node_to_neighbor_idx.get(fs)
            if nb_idx is None:
                continue

            utility = float(nodes[j].get("utility", 0.0))
            if utility <= 0:
                continue

            val = utility / (d + 3.6)

            if bool(nodes[j].get("visited", False)):
                val *= 0.2

            coord_j = tuple(np.round(nodes[j]["coords"], 6))
            if coord_j in history_set:
                val *= 0.65

            est_steps = d / 3.2
            if est_steps > steps_remaining:
                val = 0.0
            elif est_steps > steps_remaining * 0.75:
                val *= 0.25

            scores[nb_idx] += val

        # Anti-backtracking: penalize reversing the previous movement direction
        if self.prev_move_dir is not None:
            for idx, nb in enumerate(neighbors):
                move_dir = np.array(nb, dtype=float) - robot_pos
                move_dir_norm = np.linalg.norm(move_dir)
                if move_dir_norm > 1e-6:
                    move_dir = move_dir / move_dir_norm
                    dot = np.dot(move_dir, -self.prev_move_dir)
                    if dot > 0.7:
                        scores[idx] *= 0.3

        # Fallback when no aggregated utility
        if np.max(scores) < 1e-9:
            if frontiers and len(frontiers) > 0:
                frontier_arr = np.array(frontiers, dtype=float)
                best_idx = None
                best_dist = float('inf')
                for idx, nb in enumerate(neighbors):
                    nb_arr = np.array(nb, dtype=float).reshape(1, -1)
                    dists = np.linalg.norm(frontier_arr - nb_arr, axis=1)
                    min_d = np.min(dists)
                    if min_d < best_dist:
                        best_dist = min_d
                        best_idx = idx
                if best_idx is not None:
                    scores[best_idx] = 1e-6
            else:
                best_idx = None
                best_dist = float('inf')
                for idx, nb in enumerate(neighbors):
                    j = coord_to_idx.get(tuple(np.round(nb, 6)))
                    if j is None:
                        continue
                    if not bool(nodes[j].get("visited", False)):
                        d = dist[j]
                        if d < best_dist:
                            best_dist = d
                            best_idx = idx
                if best_idx is not None:
                    scores[best_idx] = 1e-6

        if np.max(scores) < 1e-9:
            scores[:] = 1.0
            for idx, nb in enumerate(neighbors):
                coord_nb = tuple(np.round(nb, 6))
                if coord_nb in history_set:
                    scores[idx] *= 0.5

        best_idx = int(np.argmax(scores))
        target = tuple(neighbors[best_idx])

        self._update_history(target)
        self.prev_move_dir = np.array(target, dtype=float) - robot_pos
        norm = np.linalg.norm(self.prev_move_dir)
        if norm > 1e-6:
            self.prev_move_dir = self.prev_move_dir / norm
        else:
            self.prev_move_dir = None

        return target


def run_episode(env, explorer):
    obs = env.reset()
    explorer.step_count = 0
    explorer.history = []
    explorer.prev_pos = None
    explorer.prev_move_dir = None
    for step in range(128):
        target = explorer.select_action(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get("done", False):
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    ckpt_path = os.path.join(args.checkpoint, "policy.pt")
    if os.path.exists(ckpt_path):
        ckpt = torch.load(ckpt_path, map_location="cpu")
        print(f"Loaded checkpoint version: {ckpt.get('version', 'unknown')}")

    eval_config_path = os.path.join(args.data_path, "eval_config.json")
    with open(eval_config_path, "r") as f:
        eval_config = json.load(f)

    # Robust parsing of eval config
    episodes = []
    if isinstance(eval_config, dict):
        if "episodes" in eval_config:
            src = eval_config["episodes"]
        elif "maps" in eval_config:
            src = eval_config["maps"]
        elif "test_maps" in eval_config:
            src = eval_config["test_maps"]
        else:
            src = []
        for item in src:
            if isinstance(item, str):
                # infer env_type from path
                parts = item.split(os.sep)
                env_type = parts[0] if parts else "unknown"
                episodes.append({"map_path": item, "env_type": env_type})
            elif isinstance(item, dict):
                mp = item.get("map_path") or item.get("path") or item.get("map")
                et = item.get("env_type", "unknown")
                if mp:
                    episodes.append({"map_path": mp, "env_type": et})

    if not episodes:
        # Scan maps_eval directory
        maps_eval_dir = os.path.join(args.data_path, "maps_eval")
        if os.path.isdir(maps_eval_dir):
            for env_type in ["room", "tunnel", "outdoor"]:
                type_dir = os.path.join(maps_eval_dir, env_type)
                if not os.path.isdir(type_dir):
                    continue
                for fname in sorted(os.listdir(type_dir)):
                    if fname.endswith(".png"):
                        episodes.append({
                            "map_path": os.path.join("maps_eval", env_type, fname),
                            "env_type": env_type
                        })

    per_episode = []
    total_explored = 0.0
    total_distance_success = 0.0
    success_count = 0
    per_type = {}

    for ep in episodes:
        map_rel_path = ep["map_path"]
        map_full_path = os.path.join(args.data_path, map_rel_path)
        env_type = ep["env_type"]

        if not os.path.exists(map_full_path):
            print(f"Warning: map not found: {map_full_path}")
            continue

        env = ExplorationEnv(map_path=map_full_path)
        explorer = Explorer()
        metrics = run_episode(env, explorer)

        success = 1 if metrics.get("success", False) else 0
        explored_rate = float(metrics.get("explored_rate", 0.0))
        travel_distance = float(metrics.get("travel_distance", 0.0))

        total_explored += explored_rate
        if success:
            total_distance_success += travel_distance
            success_count += 1

        if env_type not in per_type:
            per_type[env_type] = {
                "explored_rate_sum": 0.0,
                "travel_distance_sum": 0.0,
                "success_count": 0,
                "count": 0
            }
        per_type[env_type]["explored_rate_sum"] += explored_rate
        per_type[env_type]["travel_distance_sum"] += travel_distance
        per_type[env_type]["success_count"] += success
        per_type[env_type]["count"] += 1

        per_episode.append({
            "map_path": map_rel_path,
            "env_type": env_type,
            "success": success,
            "travel_distance": travel_distance,
            "explored_rate": explored_rate
        })

    total_episodes = len(per_episode)
    explored_rate_mean = total_explored / total_episodes if total_episodes > 0 else 0.0
    travel_distance_mean = total_distance_success / success_count if success_count > 0 else 0.0
    success_rate = success_count / total_episodes if total_episodes > 0 else 0.0

    per_type_out = {}
    for env_type, stats in per_type.items():
        count = stats["count"]
        per_type_out[env_type] = {
            "explored_rate": stats["explored_rate_sum"] / count if count > 0 else 0.0,
            "travel_distance": stats["travel_distance_sum"] / stats["success_count"] if stats["success_count"] > 0 else 0.0,
            "success_rate": stats["success_count"] / count if count > 0 else 0.0
        }

    result = {
        "explored_rate": explored_rate_mean,
        "travel_distance": travel_distance_mean,
        "success_rate": success_rate,
        "per_episode": per_episode,
        "per_type": per_type_out,
        "total_episodes": total_episodes
    }

    os.makedirs(os.path.dirname(args.output) or ".", exist_ok=True)
    with open(args.output, "w") as f:
        json.dump(result, f, indent=2)


if __name__ == "__main__":
    main()
